import React from "react";

const ContenedorLateral = ({
  subtitulo,
  imagen,
  ancho,
  alto,
  ovaloRedondez,
  cuadroRedondez,
}) => {
  // Se mantiene la lógica original para calcular el tamaño del óvalo
  const ovaloAncho = `calc(${ancho} * 0.4)`; // 40% del ancho del contenedor
  const ovaloAlto = `calc(${alto} * 0.10)`;  // 10% del alto del contenedor

  return (
    <div
      // APLICACIÓN MINIMALISTA CON PROPORCIÓN ÁUREA: Se aplican las clases de Tailwind para el color de fondo y la sombra.
      // Los estilos dinámicos se mantienen en el objeto `style`.
      className="relative flex flex-col items-center justify-start z-10 shadow-lg ml-auto bg-surface-elevated border border-stroke"
      style={{
        width: ancho,
        height: alto,
        // APLICACIÓN DE ESTILOS: Se usa el color 'primary' de tu paleta para el borde.
        borderColor: '#1E40AF', // Usamos el valor directo porque Tailwind no puede interpretar `border-primary` con un grosor dinámico en `style`.
        borderWidth: '0.618vh', // 0.618 = proporción áurea
        borderStyle: 'solid',
        borderRadius: `${cuadroRedondez} 0 0 ${cuadroRedondez}`,
        marginTop: "6.18vh", // 6.18% = proporción áurea
      }}
    >
      {/* Contenedor padre que incluye el óvalo y el contenido */}
      <div className="relative w-full h-full flex flex-col items-center justify-start">
        {/* Subtítulo en óvalo */}
        <div
          // APLICACIÓN MINIMALISTA CON PROPORCIÓN ÁUREA: Clases para fondo, sombra y layout simples.
          className="absolute bg-surface-elevated shadow-md px-[0.618rem] py-[0.618rem] flex items-center justify-center border border-stroke"
          style={{
            // Se mantiene la lógica de posicionamiento y tamaño original con proporción áurea.
            letterSpacing: "0.1618rem", // 0.1618 = proporción áurea
            fontSize: "clamp(1rem, 2.618vw, 1.854rem)", // 2.618 = proporción áurea
            borderRadius: ovaloRedondez,
            left: "38.2%", // 38.2% = proporción áurea
            top: "-6.18%", // 6.18% = proporción áurea
            transform: "translateX(-50%)",
            maxWidth: ovaloAncho,
            width: "100%",
            height: ovaloAlto,
            // APLICACIÓN DE ESTILOS: Se usa el color 'stroke' para el borde.
            borderColor: '#E5E7EB',
            borderWidth: '0.1618vh', // 0.1618 = proporción áurea
            borderStyle: 'solid',
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
          }}
        >
          {/* APLICACIÓN MINIMALISTA: Se aplica la fuente Bodoni y color sólido azul. */}
          <span className="font-bodoni text-primary font-bold">
            {subtitulo}
          </span>
        </div>

        {/* Contenido dentro del contenedor - Proporción áurea en espaciados */}
        <div
          className="w-full text-sm text-center"
          style={{
            marginTop: "6.18vw", // 6.18% = proporción áurea
          }}
        >
          {/* Contenedor de la imagen - Proporción áurea en dimensiones */}
          <div
            style={{
              width: "38.2vw", // 38.2% = proporción áurea
              height: "61.8vw", // 61.8% = proporción áurea
              display: "flex",
              transform: "translate(38.2%, -6.18%)", // 38.2% y 6.18% = proporción áurea
              overflow: "hidden",
            }}
          >
            <img
              src={imagen}
              alt="contenido dinámico"
              className="object-contain transition-transform duration-300 hover:scale-105" // object-contain es suficiente, el resto se controla en `style`
              style={{
                width: "100%",
                height: "100%",
                borderRadius: ovaloRedondez,
                display: "block",
                margin: "0 auto",
              }}
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default ContenedorLateral;
